#include <stdio.h>
#include <stdlib.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long diff = llabs(X - Y);
        long long ans = (diff + 1) / 2;
        printf("%lld\n", ans);
    }
    return 0;
}

